			fields: [scalingLevelsTable.scalingGroupId],
			references: [scalingGroupsTable.id],
		}),
		workoutDescriptions: many(workoutScalingDescriptionsTable),
	}),
)

export const workoutScalingDescriptionsRelations = relations(
