				userId: result.userId,
			},
		})
		throw slackErr
	}
}

// =========================================================================
// Cloudflare Workflow class (production — durable execution with retries)
// =========================================================================

export class StripeCheckoutWorkflow extends WorkflowEntrypoint<
	Env,
	CheckoutCompletedParams
